import React from 'react';

const Header: React.FC = () => {
  return (
    <header className="py-6 px-4 sm:px-6 lg:px-8 text-center">
      <div className="flex items-center justify-center space-x-4">
        <i className="fa-solid fa-music text-3xl md:text-4xl text-white"></i>
        <h1 className="text-[28px] md:text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-white via-neutral-300 to-neutral-500">
          AI Mood Music
        </h1>
      </div>
      <p className="mt-2 text-md md:text-lg text-neutral-500">
        Tell us how you feel, and we'll find the perfect soundtrack for your mood.
      </p>
    </header>
