export default Header;

import React, { useState } from 'react';

interface MoodInputFormProps {
  onSubmit: (text: string) => void;
  isLoading: boolean;
}

const MoodInputForm: React.FC<MoodInputFormProps> = ({ onSubmit, isLoading }) => {
  const [text, setText] = useState('');

  const examples = [
    "I had an amazing day, feeling on top of the world!",
    "Work was so stressful, I need to unwind.",
    "I have a big presentation tomorrow and I'm so anxious.",
    "Feeling a bit lonely and nostalgic tonight.",
  ];

  const handleExampleClick = (example: string) => {
    setText(example);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onSubmit(text);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-2xl mx-auto space-y-4">
      <textarea
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="e.g., 'I'm feeling happy today' or 'I'm stressed out'"
        className="w-full h-28 p-4 bg-[#0a0a0a] border border-neutral-800 rounded-lg text-neutral-200 placeholder-neutral-600 focus:outline-none focus:border-neutral-500 focus:shadow-input-focus transition-all duration-300 resize-none"
        disabled={isLoading}
      />
      <div className="flex flex-wrap gap-2 justify-center">
        {examples.map((ex, index) => (
            <button
                key={index}
                type="button"
                onClick={() => handleExampleClick(ex)}
                disabled={isLoading}
                className="px-3 py-1 text-xs bg-neutral-900 border border-neutral-800 text-neutral-400 rounded-full hover:bg-neutral-800 hover:text-neutral-200 transition-colors duration-200"
            >
                {ex.split(' ').slice(0, 4).join(' ')}...
            </button>
        ))}
      </div>
      <button
        type="submit"
        disabled={isLoading || !text.trim()}
        className="w-full flex items-center justify-center h-[44px] px-6 bg-gradient-to-r from-primary to-secondary text-white font-medium rounded-btn shadow-btn-primary disabled:opacity-50 disabled:shadow-none disabled:cursor-not-allowed transform hover:-translate-y-0.5 transition-all duration-300 border border-white/5"
      >
        {isLoading ? (
          <>
            <i className="fa-solid fa-spinner fa-spin mr-2"></i>
            Finding Your Vibe...
          </>
        ) : (
          <>
            <i className="fa-solid fa-wand-magic-sparkles mr-2"></i>
            Get Recommendations
          </>
        )}
      </button>
    </form>
  );
};

export default MoodInputForm;

import React, { useState } from 'react';
import { Song } from '../types';

interface SongCardProps {
  song: Song;
  index: number;
  onSelectSong: (index: number) => void;
  isCurrentlySelected: boolean;
  isPlaying: boolean;
}

const SongCard: React.FC<SongCardProps> = ({ song, index, onSelectSong, isCurrentlySelected, isPlaying }) => {
  const [imageError, setImageError] = useState(false);

  const handleImageError = () => {
    setImageError(true);
  };

  const showPlayIcon = !isCurrentlySelected || !isPlaying;

  return (
    <div
      className={`bg-gradient-to-br p-4 rounded-card shadow-card flex items-center space-x-4 transform transition-all duration-300 hover:-translate-y-1.5 hover:shadow-card-hover border border-white/5 ${isCurrentlySelected ? 'from-neutral-800 to-neutral-900 border-neutral-600' : 'from-neutral-900 to-black border-neutral-800'}`}
      style={{ animation: `fadeInUp 0.5s ease-out ${index * 0.1}s forwards`, opacity: 0 }}
    >
      <div className="relative flex-shrink-0 w-16 h-16">
        {song.albumArtUrl && !imageError ? (
          <img
            src={song.albumArtUrl}
            alt={`Album art for ${song.title}`}
            className="w-full h-full bg-neutral-800 rounded-lg object-cover grayscale hover:grayscale-0 transition-all duration-500"
            onError={handleImageError}
          />
        ) : (
          <div className="w-full h-full bg-neutral-800 rounded-lg flex items-center justify-center">
            <i className="fa-solid fa-music text-3xl text-neutral-600"></i>
          </div>
        )}
        {song.previewUrl && (
          <button
            onClick={() => onSelectSong(index)}
            className={`absolute inset-0 w-full h-full bg-black/60 rounded-lg flex items-center justify-center text-white text-2xl transition-opacity duration-300 ${isCurrentlySelected ? 'opacity-100' : 'opacity-0 hover:opacity-100 focus:opacity-100'}`}
            aria-label={showPlayIcon ? `Play preview for ${song.title}` : `Pause preview for ${song.title}`}
          >
            <i className={`fa-solid ${showPlayIcon ? 'fa-play' : 'fa-pause'}`}></i>
          </button>
        )}
      </div>

      <div className="flex-1 min-w-0">
        <p className="text-lg font-semibold text-neutral-100 truncate">{song.title}</p>
        <p className="text-sm text-neutral-500 truncate">{song.artist}</p>
      </div>
      <a
        href={song.spotifyUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="flex-shrink-0 px-4 h-9 text-xs font-semibold text-black bg-white rounded-full hover:bg-neutral-200 transition-colors duration-200 flex items-center space-x-2 transform hover:scale-105"
        aria-label={`Listen to ${song.title} by ${song.artist} on Spotify`}
      >
        <i className="fa-brands fa-spotify"></i>
        <span>Listen</span>
      </a>
    </div>
  );
};

export default SongCard;

import React, { useState, useRef, useEffect } from 'react';
import Header from './Header';
import MoodInputForm from './MoodInputForm';
import SongCard from './SongCard';
import Loader from './Loader';
import Footer from './Footer';
import AudioPlayer from './AudioPlayer';
import { Song, Mood } from '../types';
import { getMoodAndRecommendations } from '../services/geminiService';

const MusicRecommender: React.FC = () => {
  const [recommendations, setRecommendations] = useState<Song[] | null>(null);
  const [mood, setMood] = useState<Mood | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // New player state
  const [currentSongIndex, setCurrentSongIndex] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [volume, setVolume] = useState(1);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  // Use a ref to hold the latest version of the handleNextSong function
  // to avoid stale closures in event listeners and callbacks.
  const handleNextSongRef = useRef<() => void>();


  const findNextPlayableSong = (startIndex: number, direction: 1 | -1): number | null => {
    if (!recommendations || recommendations.length < 2) return null;
    let nextIndex = (startIndex + direction + recommendations.length) % recommendations.length;
    const initialIndex = startIndex;
    while (!recommendations[nextIndex].previewUrl) {
        nextIndex = (nextIndex + direction + recommendations.length) % recommendations.length;
        if (nextIndex === initialIndex) return null; // Cycled through all songs, none are playable
    }
    return nextIndex;
  };

  const handleNextSong = () => {
    if (currentSongIndex === null) return;
    const nextIndex = findNextPlayableSong(currentSongIndex, 1);
    if (nextIndex !== null) {
      setCurrentSongIndex(nextIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false); // No other playable songs found
    }
  };

  // Keep the ref updated with the latest version of the handler function on every render.
  useEffect(() => {
    handleNextSongRef.current = handleNextSong;
  });

  // Effect to initialize and manage the audio element and its listeners (runs only once)
  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = volume;

    const audio = audioRef.current;

    const onTimeUpdate = () => {
      if (audio.duration) {
        setProgress((audio.currentTime / audio.duration) * 100);
        setCurrentTime(audio.currentTime);
      }
    };
    const onLoadedMetadata = () => {
      setDuration(audio.duration);
    };

    // Call the latest handler from the ref to avoid stale state.
    const onEnded = () => {
      handleNextSongRef.current?.();
    };

    // FIX: When an audio source fails to load, automatically skip to the next song.
    const onError = () => {
      console.error("Error playing audio source. Skipping to the next available song.");
      handleNextSongRef.current?.();
    };

    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('loadedmetadata', onLoadedMetadata);
    audio.addEventListener('ended', onEnded);
    audio.addEventListener('error', onError);

    return () => {
      audio.removeEventListener('timeupdate', onTimeUpdate);
      audio.removeEventListener('loadedmetadata', onLoadedMetadata);
      audio.removeEventListener('ended', onEnded);
      audio.removeEventListener('error', onError);
      audio.pause();
    };
  }, []); // Empty dependency array ensures this runs only on mount.

  // Effect to update audio volume
  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.volume = volume;
    }
  }, [volume]);

  // Effect to handle song changes and play/pause
  useEffect(() => {
    if (!recommendations || currentSongIndex === null || !audioRef.current) return;

    const song = recommendations[currentSongIndex];
    if (song?.previewUrl) {
      if (audioRef.current.src !== song.previewUrl) {
        audioRef.current.src = song.previewUrl;
      }

      if (isPlaying) {
        audioRef.current.play().catch(e => {
            // The 'error' event listener handles this, but we can call it here as a fallback.
            console.error("Audio playback promise rejected:", e);
            handleNextSongRef.current?.();
        });
      } else {
        audioRef.current.pause();
      }
    } else if (isPlaying) {
      // If the current song has no preview URL but we are in a "playing" state,
      // immediately try to play the next available song.
      handleNextSongRef.current?.();
    } else {
      // If the selected song has no preview and we're not playing, just pause.
      setIsPlaying(false);
      audioRef.current.pause();
    }
  }, [currentSongIndex, isPlaying, recommendations]);


  const handleSelectSong = (index: number) => {
    if (!recommendations?.[index]?.previewUrl) return;
    if (currentSongIndex === index) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentSongIndex(index);
      setIsPlaying(true);
    }
  };

  const handlePlayPause = () => {
    if (currentSongIndex !== null) {
      setIsPlaying(!isPlaying);
    }
  };

  const handlePrevSong = () => {
    if (currentSongIndex === null) return;
    const prevIndex = findNextPlayableSong(currentSongIndex, -1);
    if (prevIndex !== null) {
      setCurrentSongIndex(prevIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (audioRef.current && duration) {
        const newProgress = Number(e.target.value);
        const newTime = (newProgress / 100) * duration;
        audioRef.current.currentTime = newTime;
        setProgress(newProgress);
    }
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = Number(e.target.value);
    setVolume(newVolume);
  };

  const handleSubmit = async (text: string) => {
    setIsLoading(true);
    setError(null);
    setRecommendations(null);
    setMood(null);

    // Reset player state
    if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = '';
    }
    setCurrentSongIndex(null);
    setIsPlaying(false);
    setProgress(0);
    setCurrentTime(0);
    setDuration(0);

    try {
      const response = await getMoodAndRecommendations(text);
      setRecommendations(response.songs);
      setMood(response.mood);
    } catch (err: unknown) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError("An unexpected error occurred.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleShuffle = () => {
    if (recommendations) {
        const shuffled = [...recommendations];
        let currentIndex = shuffled.length;
        let randomIndex;
        while (currentIndex !== 0) {
            randomIndex = Math.floor(Math.random() * currentIndex);
            currentIndex--;
            [shuffled[currentIndex], shuffled[randomIndex]] = [
            shuffled[randomIndex], shuffled[currentIndex]];
        }
        setRecommendations(shuffled);
    }
  };

  const getMoodEmoji = (currentMood: Mood | null): string => {
    switch (currentMood) {
      case Mood.Happy: return '😄';
      case Mood.Sad: return '😢';
      case Mood.Angry: return '😠';
      case Mood.Relaxed: return '😌';
      case Mood.Energetic: return '⚡️';
      case Mood.Lonely: return '😔';
      case Mood.Hopeful: return '✨';
      case Mood.Stressed: return '😩';
      case Mood.Romantic: return '😍';
      case Mood.Focused: return '🎯';
      case Mood.Nostalgic: return '🕰️';
      case Mood.Anxious: return '😟';
      default: return '🎶';
    }
  };

  const getGradientForMood = (currentMood: Mood | null): string => {
    // Neutral theme: All moods use the same sleek monochromatic gradient
    return 'from-neutral-800 to-neutral-900 border border-neutral-700';
  }

  const currentSong = currentSongIndex !== null && recommendations ? recommendations[currentSongIndex] : null;

  return (
    <div style={{ animation: `fadeIn 0.5s ease-out forwards`}} className="pb-28">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8 flex flex-col items-center">
        <div className="w-full">
          <MoodInputForm onSubmit={handleSubmit} isLoading={isLoading} />
        </div>

        <div className="w-full max-w-2xl mt-8">
          {isLoading && <Loader />}

          {error && (
            <div className="bg-neutral-900 border border-neutral-700 text-neutral-300 p-4 rounded-lg text-center" role="alert">
              <p className="font-bold text-white">Oops! Something went wrong.</p>
              <p>{error}</p>
            </div>
          )}

          {recommendations && mood && (
            <div className="space-y-4">
              <div className="flex justify-between items-center gap-4">
                <h2 className={`flex-grow text-2xl font-bold text-center text-white p-4 rounded-lg shadow-lg bg-gradient-to-r ${getGradientForMood(mood)}`}>
                  {getMoodEmoji(mood)} Songs for your {mood} mood
                </h2>
                {recommendations.length > 1 && (
                    <button
                        onClick={handleShuffle}
                        className="flex-shrink-0 w-12 h-12 flex items-center justify-center bg-neutral-800 border border-neutral-700 text-white rounded-full hover:bg-neutral-700 transition-all duration-200 transform hover:scale-105"
                        aria-label="Shuffle recommendations"
                        title="Shuffle recommendations"
                    >
                        <i className="fa-solid fa-shuffle text-xl"></i>
                    </button>
                )}
              </div>
              <p className="text-center text-neutral-500 text-sm">
                Found {recommendations.length} {recommendations.length === 1 ? 'song' : 'songs'} matching your vibe.
              </p>
              <div className="grid grid-cols-1 gap-4 mt-4">
                {recommendations.map((song, index) => (
                  <SongCard 
                    key={`${song.title}-${song.artist}-${index}`} 
                    song={song} 
                    index={index}
                    onSelectSong={handleSelectSong}
                    isCurrentlySelected={currentSongIndex === index}
                    isPlaying={isPlaying}
                  />
                ))}
              </div>
            </div>
          )}

          {!isLoading && !error && !recommendations && (
             <div className="text-center text-neutral-600 mt-12 p-6 border-2 border-dashed border-neutral-800 rounded-lg">
                <i className="fa-solid fa-headphones text-4xl mb-4"></i>
                <p>Your personalized playlist awaits.</p>
             </div>
          )}
        </div>
      </main>
      <Footer />
      <AudioPlayer 
        song={currentSong}
        isPlaying={isPlaying}
        progress={progress}
        volume={volume}
        duration={duration}
        currentTime={currentTime}
        onPlayPause={handlePlayPause}
        onNext={handleNextSong}
        onPrev={handlePrevSong}
        onSeek={handleSeek}
        onVolumeChange={handleVolumeChange}
      />
    </div>
  );
};

export default MusicRecommender;

