import React from 'react';
import { Song } from '../types';

interface AudioPlayerProps {
  song: Song | null;
  isPlaying: boolean;
  progress: number;
  duration: number;
  currentTime: number;
  volume: number;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  onSeek: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onVolumeChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const formatTime = (seconds: number) => {
  if (isNaN(seconds) || seconds < 0) return '0:00';
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = Math.floor(seconds % 60);
  return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
};

const AudioPlayer: React.FC<AudioPlayerProps> = ({
  song,
  isPlaying,
  progress,
  duration,
  currentTime,
  volume,
  onPlayPause,
  onNext,
  onPrev,
  onSeek,
  onVolumeChange,
}) => {
  if (!song) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 animate-fadeInUp" style={{ animation: `fadeInUp 0.3s ease-out forwards`, opacity: 0 }}>
      <div className="bg-black/90 backdrop-blur-lg border-t border-neutral-800 p-3 flex items-center gap-4 text-white">

        <div className="flex items-center gap-3 w-64 flex-shrink-0">
          <img
            src={song.albumArtUrl}
            alt={song.title}
            className="w-14 h-14 rounded-md object-cover bg-neutral-800 grayscale"
          />
          <div className="min-w-0">
            <p className="font-bold truncate text-sm text-white">{song.title}</p>
            <p className="text-xs text-neutral-400 truncate">{song.artist}</p>
          </div>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center gap-2 max-w-lg mx-auto">
          <div className="flex items-center gap-6">
            <button onClick={onPrev} className="text-lg text-neutral-400 hover:text-white transition-colors" aria-label="Previous song">
              <i className="fa-solid fa-backward-step"></i>
            </button>
            <button
              onClick={onPlayPause}
              className="w-10 h-10 flex items-center justify-center bg-white rounded-full text-black text-lg hover:bg-neutral-200 transition-transform transform hover:scale-105"
              aria-label={isPlaying ? 'Pause' : 'Play'}
            >
              <i className={`fa-solid ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i>
            </button>
            <button onClick={onNext} className="text-lg text-neutral-400 hover:text-white transition-colors" aria-label="Next song">
              <i className="fa-solid fa-forward-step"></i>
            </button>
          </div>
          <div className="w-full flex items-center gap-2 text-xs text-neutral-400">
            <span>{formatTime(currentTime)}</span>
            <input
              type="range"
              value={progress || 0}
              onChange={onSeek}
              className="w-full h-1 bg-neutral-800 rounded-full appearance-none cursor-pointer accent-white"
              aria-label="Song progress"
            />
            <span>{formatTime(duration)}</span>
          </div>
        </div>

        <div className="w-64 flex-shrink-0 flex justify-end items-center gap-2">
          <i className={`fa-solid text-neutral-400 ${volume > 0.5 ? 'fa-volume-high' : volume > 0 ? 'fa-volume-low' : 'fa-volume-xmark'}`}></i>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={volume}
            onChange={onVolumeChange}
            className="w-24 h-1 bg-neutral-800 rounded-full appearance-none cursor-pointer accent-white"
            aria-label="Volume control"
          />
        </div>
      </div>
    </div>
  );
};

