  onReorder: (fromIndex: number, toIndex: number) => void;
}

const SongQueue: React.FC<SongQueueProps> = ({
  songs,
  currentSongIndex,
  isOpen,
  onClose,
  onSelect,
  onReorder,
}) => {
  return (
    <div
      className={`fixed inset-y-0 right-0 w-full sm:w-96 bg-slate-900/95 backdrop-blur-xl border-l border-slate-800 shadow-2xl transform transition-transform duration-300 ease-in-out z-40 flex flex-col ${
        isOpen ? 'translate-x-0' : 'translate-x-full'
