    >
      <div className="p-6 border-b border-slate-800 flex items-center justify-between bg-slate-900/50">
        <div>
            <h2 className="text-xl font-bold text-white">Queue</h2>
            <p className="text-xs text-slate-400 mt-1">Next up from your mood</p>
        </div>
        <button
          onClick={onClose}
          className="w-8 h-8 rounded-full bg-slate-800 text-slate-400 hover:text-white hover:bg-slate-700 flex items-center justify-center transition-colors"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2 pb-32">
        {songs.map((song, index) => {
          const isCurrent = currentSongIndex === index;
          return (
            <div
              key={`${song.title}-${index}`}
              className={`group flex items-center gap-3 p-3 rounded-xl transition-all ${
                isCurrent
                  ? 'bg-indigo-500/10 border border-indigo-500/30'
                  : 'hover:bg-slate-800/50 border border-transparent hover:border-slate-700'
              }`}
            >
              <div 
                onClick={() => onSelect(index)}
                className="relative w-10 h-10 flex-shrink-0 cursor-pointer"
              >
                <img
                  src={song.albumArtUrl}
                  alt={song.title}
                  className={`w-full h-full rounded object-cover ${isCurrent ? 'opacity-50' : ''}`}
                />
                {isCurrent && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-1 h-3 bg-indigo-400 mx-[1px] animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-1 h-4 bg-indigo-400 mx-[1px] animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-1 h-3 bg-indigo-400 mx-[1px] animate-bounce" style={{ animationDelay: '300ms' }}></div>
                  </div>
                )}
                {!isCurrent && (
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded transition-opacity">
                         <i className="fa-solid fa-play text-white text-xs"></i>
                    </div>
                )}
              </div>

              <div className="flex-1 min-w-0" onClick={() => onSelect(index)}>
                <p className={`text-sm font-semibold truncate ${isCurrent ? 'text-indigo-300' : 'text-slate-200'}`}>
                  {song.title}
                </p>
                <p className="text-xs text-slate-500 truncate">{song.artist}</p>
              </div>

              <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    if (index > 0) onReorder(index, index - 1);
                  }}
                  disabled={index === 0}
                  className="w-6 h-6 rounded flex items-center justify-center text-slate-500 hover:text-indigo-400 hover:bg-slate-700 disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:text-slate-500"
