interface AudioPlayerProps {
  song: Song | null;
  isPlaying: boolean;
  progress: number;
  duration: number;
  currentTime: number;
  volume: number;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  onSeek: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onVolumeChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onToggleQueue: () => void;
  isQueueOpen: boolean;
}

const formatTime = (seconds: number) => {
  if (isNaN(seconds) || seconds < 0) return '0:00';
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = Math.floor(seconds % 60);
  return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
};

const AudioPlayer: React.FC<AudioPlayerProps> = ({
  song,
  isPlaying,
  progress,
  duration,
  currentTime,
  volume,
  onPlayPause,
  onNext,
  onPrev,
  onSeek,
  onVolumeChange,
  onToggleQueue,
  isQueueOpen,
}) => {
  if (!song) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 animate-fadeInUp" style={{ animation: `fadeInUp 0.3s ease-out forwards`, opacity: 0 }}>
      <div className="bg-[#020617]/95 backdrop-blur-xl border-t border-indigo-500/20 px-4 py-3 shadow-[0_-4px_20px_rgba(0,0,0,0.4)]">
        <div className="container mx-auto flex items-center justify-between gap-4">

            <div className="flex items-center gap-4 w-1/4 min-w-[200px]">
              <div className="relative group">
                  <img
                    src={song.albumArtUrl}
                    alt={song.title}
                    className={`w-14 h-14 rounded-lg object-cover shadow-lg border border-slate-700 ${isPlaying ? 'animate-pulse-slow' : ''}`}
                  />
                  <div className="absolute inset-0 bg-black/20 rounded-lg"></div>
              </div>
              <div className="min-w-0 overflow-hidden">
                <div className="font-bold text-white truncate text-sm leading-tight">{song.title}</div>
                <div className="text-xs text-indigo-300 truncate mt-0.5">{song.artist}</div>
              </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center max-w-lg">
              <div className="flex items-center gap-8 mb-1">
                <button onClick={onPrev} className="text-slate-400 hover:text-white transition-colors p-2" aria-label="Previous song">
                  <i className="fa-solid fa-backward-step text-lg"></i>
                </button>
                <button
                  onClick={onPlayPause}
                  className="w-10 h-10 flex items-center justify-center bg-white rounded-full text-indigo-600 shadow-lg shadow-indigo-500/20 hover:scale-105 hover:bg-indigo-50 transition-all duration-200"
                  aria-label={isPlaying ? 'Pause' : 'Play'}
                >
                  <i className={`fa-solid ${isPlaying ? 'fa-pause' : 'fa-play ml-0.5'}`}></i>
                </button>
                <button onClick={onNext} className="text-slate-400 hover:text-white transition-colors p-2" aria-label="Next song">
                  <i className="fa-solid fa-forward-step text-lg"></i>
                </button>
              </div>
              <div className="w-full flex items-center gap-3 text-[10px] font-medium text-slate-400 font-mono">
