                  type="range"
                  value={progress || 0}
                  onChange={onSeek}
                  className="w-full h-1 bg-slate-700 rounded-full appearance-none cursor-pointer accent-primary focus:outline-none hover:h-1.5 transition-all"
                  aria-label="Song progress"
                />
                <span className="w-8">{formatTime(duration)}</span>
              </div>
            </div>

            <div className="w-1/4 min-w-[150px] flex justify-end items-center gap-3">
              <button 
                onClick={onToggleQueue}
                className={`p-2 rounded-lg transition-colors ${isQueueOpen ? 'text-indigo-400 bg-indigo-500/10' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                title="Queue"
              >
                <i className="fa-solid fa-list-ul"></i>
              </button>

              <div className="h-4 w-[1px] bg-slate-700 mx-1"></div>

              <i className={`fa-solid text-slate-400 ${volume > 0.5 ? 'fa-volume-high' : volume > 0 ? 'fa-volume-low' : 'fa-volume-xmark'} text-xs`}></i>
              <input
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={volume}
                onChange={onVolumeChange}
                className="w-20 h-1 bg-slate-700 rounded-full appearance-none cursor-pointer accent-primary focus:outline-none"
                aria-label="Volume control"
              />
            </div>
        </div>
      </div>
    </div>
  );
};

export default AudioPlayer;

import React, { useState, useRef, useEffect } from 'react';
import Header from './Header';
import MoodInputForm from './MoodInputForm';
import SongCard from './SongCard';
import Loader from './Loader';
import Footer from './Footer';
import AudioPlayer from './AudioPlayer';
import SongQueue from './SongQueue';
import { Song, Mood } from '../types';
import { getMoodAndRecommendations } from '../services/geminiService';

const MusicRecommender: React.FC = () => {
  const [recommendations, setRecommendations] = useState<Song[] | null>(null);
  const [mood, setMood] = useState<Mood | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // New player state
  const [currentSongIndex, setCurrentSongIndex] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [volume, setVolume] = useState(1);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);

  // Queue State
  const [isQueueOpen, setIsQueueOpen] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  // Use a ref to hold the latest version of the handleNextSong function
  // to avoid stale closures in event listeners and callbacks.
  const handleNextSongRef = useRef<() => void>();


  const findNextPlayableSong = (startIndex: number, direction: 1 | -1): number | null => {
    if (!recommendations || recommendations.length < 2) return null;
    let nextIndex = (startIndex + direction + recommendations.length) % recommendations.length;
    const initialIndex = startIndex;
    while (!recommendations[nextIndex].previewUrl) {
        nextIndex = (nextIndex + direction + recommendations.length) % recommendations.length;
        if (nextIndex === initialIndex) return null; // Cycled through all songs, none are playable
    }
    return nextIndex;
  };

  const handleNextSong = () => {
    if (currentSongIndex === null) return;
    const nextIndex = findNextPlayableSong(currentSongIndex, 1);
    if (nextIndex !== null) {
      setCurrentSongIndex(nextIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false); // No other playable songs found
    }
  };

  // Keep the ref updated with the latest version of the handler function on every render.
  useEffect(() => {
    handleNextSongRef.current = handleNextSong;
  });

  // Effect to initialize and manage the audio element and its listeners (runs only once)
  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = volume;

    const audio = audioRef.current;

    const onTimeUpdate = () => {
      if (audio.duration) {
        setProgress((audio.currentTime / audio.duration) * 100);
        setCurrentTime(audio.currentTime);
      }
    };
    const onLoadedMetadata = () => {
      setDuration(audio.duration);
    };

    // Call the latest handler from the ref to avoid stale state.
    const onEnded = () => {
      handleNextSongRef.current?.();
    };

    // FIX: When an audio source fails to load, automatically skip to the next song.
    const onError = () => {
      console.error("Error playing audio source. Skipping to the next available song.");
      handleNextSongRef.current?.();
    };

    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('loadedmetadata', onLoadedMetadata);
    audio.addEventListener('ended', onEnded);
    audio.addEventListener('error', onError);

    return () => {
      audio.removeEventListener('timeupdate', onTimeUpdate);
      audio.removeEventListener('loadedmetadata', onLoadedMetadata);
      audio.removeEventListener('ended', onEnded);
      audio.removeEventListener('error', onError);
      audio.pause();
    };
  }, []); // Empty dependency array ensures this runs only on mount.

  // Effect to update audio volume
  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.volume = volume;
    }
  }, [volume]);

  // Effect to handle song changes and play/pause
  useEffect(() => {
    if (!recommendations || currentSongIndex === null || !audioRef.current) return;

    const song = recommendations[currentSongIndex];
    if (song?.previewUrl) {
      if (audioRef.current.src !== song.previewUrl) {
        audioRef.current.src = song.previewUrl;
      }

      if (isPlaying) {
        audioRef.current.play().catch(e => {
            // The 'error' event listener handles this, but we can call it here as a fallback.
            console.error("Audio playback promise rejected:", e);
            handleNextSongRef.current?.();
        });
      } else {
        audioRef.current.pause();
      }
    } else if (isPlaying) {
      // If the current song has no preview URL but we are in a "playing" state,
      // immediately try to play the next available song.
      handleNextSongRef.current?.();
    } else {
      // If the selected song has no preview and we're not playing, just pause.
      setIsPlaying(false);
      audioRef.current.pause();
    }
  }, [currentSongIndex, isPlaying, recommendations]);


  const handleSelectSong = (index: number) => {
    if (!recommendations?.[index]?.previewUrl) return;
    if (currentSongIndex === index) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentSongIndex(index);
      setIsPlaying(true);
    }
  };

  const handlePlayPause = () => {
    if (currentSongIndex !== null) {
      setIsPlaying(!isPlaying);
    }
  };

  const handlePrevSong = () => {
    if (currentSongIndex === null) return;
    const prevIndex = findNextPlayableSong(currentSongIndex, -1);
    if (prevIndex !== null) {
      setCurrentSongIndex(prevIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (audioRef.current && duration) {
        const newProgress = Number(e.target.value);
        const newTime = (newProgress / 100) * duration;
        audioRef.current.currentTime = newTime;
        setProgress(newProgress);
    }
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = Number(e.target.value);
    setVolume(newVolume);
  };

  const handleSubmit = async (text: string) => {
    setIsLoading(true);
    setError(null);
    setRecommendations(null);
    setMood(null);
    setIsQueueOpen(false);

    // Reset player state
    if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = '';
    }
    setCurrentSongIndex(null);
    setIsPlaying(false);
    setProgress(0);
    setCurrentTime(0);
    setDuration(0);

    try {
      const response = await getMoodAndRecommendations(text);
      setRecommendations(response.songs);
      setMood(response.mood);
    } catch (err: unknown) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError("An unexpected error occurred.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleShuffle = () => {
    if (recommendations) {
        const shuffled = [...recommendations];
        let currentIndex = shuffled.length;
        let randomIndex;
        while (currentIndex !== 0) {
            randomIndex = Math.floor(Math.random() * currentIndex);
            currentIndex--;
            [shuffled[currentIndex], shuffled[randomIndex]] = [
            shuffled[randomIndex], shuffled[currentIndex]];
        }
        setRecommendations(shuffled);
        // Reset current index if shuffling, or find where the current song went (complex),
        // Simplest is to just stop playing or start from top.
        // Better UX: keep playing current song, but shuffle the rest?
        // For simplicity: restart playlist.
        setCurrentSongIndex(0);
        setIsPlaying(false); 
    }
  };

  const handleReorder = (fromIndex: number, toIndex: number) => {
    if (!recommendations) return;

    const newSongs = [...recommendations];
    // Swap
    [newSongs[fromIndex], newSongs[toIndex]] = [newSongs[toIndex], newSongs[fromIndex]];
    setRecommendations(newSongs);

    // If we moved the currently playing song, update the index so playback doesn't jump
    if (currentSongIndex === fromIndex) {
        setCurrentSongIndex(toIndex);
    } else if (currentSongIndex === toIndex) {
        setCurrentSongIndex(fromIndex);
    }
  };

  const getMoodEmoji = (currentMood: Mood | null): string => {
    switch (currentMood) {
      case Mood.Happy: return '😄';
      case Mood.Sad: return '😢';
      case Mood.Angry: return '😠';
      case Mood.Relaxed: return '😌';
      case Mood.Energetic: return '⚡️';
      case Mood.Lonely: return '😔';
      case Mood.Hopeful: return '✨';
      case Mood.Stressed: return '😩';
      case Mood.Romantic: return '😍';
      case Mood.Focused: return '🎯';
      case Mood.Nostalgic: return '🕰️';
      case Mood.Anxious: return '😟';
      default: return '🎶';
    }
  };

  const currentSong = currentSongIndex !== null && recommendations ? recommendations[currentSongIndex] : null;

  return (
    <div style={{ animation: `fadeIn 0.5s ease-out forwards`}} className="pb-32 relative">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8 flex flex-col items-center">
        <div className="w-full">
          <MoodInputForm onSubmit={handleSubmit} isLoading={isLoading} />
        </div>

        <div className="w-full max-w-2xl mt-12">
          {isLoading && <Loader />}

          {error && (
            <div className="bg-red-900/20 border border-red-500/30 text-red-200 p-6 rounded-xl text-center backdrop-blur-sm" role="alert">
              <i className="fa-solid fa-triangle-exclamation text-2xl mb-2 text-red-400"></i>
              <p className="font-semibold">Oops! Something went wrong.</p>
              <p className="text-sm mt-1 opacity-80">{error}</p>
            </div>
          )}

          {recommendations && mood && (
            <div className="space-y-6">
              <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 shadow-xl backdrop-blur-md">
                <div className="flex flex-col sm:flex-row justify-between items-center gap-4 mb-2">
                    <div className="flex items-center gap-3">
                        <div className="text-4xl">{getMoodEmoji(mood)}</div>
                        <div>
                             <h2 className="text-2xl font-bold text-white">
                                {mood} <span className="text-slate-400 font-normal">Vibes</span>
                            </h2>
                            <p className="text-indigo-300 text-sm">
                                Found {recommendations.length} tracks for you
                            </p>
                        </div>
                    </div>

                    {recommendations.length > 1 && (
                        <button
                            onClick={handleShuffle}
                            className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg transition-colors text-sm font-medium border border-slate-700 hover:border-indigo-500/50"
                        >
                            <i className="fa-solid fa-shuffle"></i>
                            Shuffle
                        </button>
                    )}
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                {recommendations.map((song, index) => (
                  <SongCard 
                    key={`${song.title}-${song.artist}-${index}`} 
                    song={song} 
                    index={index}
                    onSelectSong={handleSelectSong}
                    isCurrentlySelected={currentSongIndex === index}
                    isPlaying={isPlaying}
                  />
                ))}
              </div>
            </div>
          )}

          {!isLoading && !error && !recommendations && (
             <div className="text-center text-slate-600 mt-12 p-10 border-2 border-dashed border-slate-800 rounded-2xl bg-slate-900/30">
                <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fa-solid fa-headphones text-2xl text-slate-500"></i>
                </div>
                <p className="text-lg font-medium text-slate-500">Your personalized playlist awaits.</p>
                <p className="text-sm text-slate-600">Enter your mood above to get started.</p>
             </div>
          )}
        </div>
      </main>
      <Footer />

      {recommendations && (
        <SongQueue 
            songs={recommendations}
            currentSongIndex={currentSongIndex}
            isOpen={isQueueOpen}
            onClose={() => setIsQueueOpen(false)}
            onSelect={handleSelectSong}
            onReorder={handleReorder}
        />
      )}

      <AudioPlayer 
        song={currentSong}
        isPlaying={isPlaying}
        progress={progress}
        volume={volume}
        duration={duration}
        currentTime={currentTime}
        onPlayPause={handlePlayPause}
        onNext={handleNextSong}
        onPrev={handlePrevSong}
        onSeek={handleSeek}
        onVolumeChange={handleVolumeChange}
        onToggleQueue={() => setIsQueueOpen(!isQueueOpen)}
        isQueueOpen={isQueueOpen}
      />
    </div>
  );
};

