  song, 
  index, 
  onSelectSong, 
  isCurrentlySelected, 
  isPlaying,
  isFavorite,
  onToggleFavorite
}) => {
  const [imageError, setImageError] = useState(false);

  const handleImageError = () => {
    setImageError(true);
  };

