              aria-label={showPlayIcon ? `Play preview for ${song.title}` : `Pause preview for ${song.title}`}
            >
              <i className={`fa-solid ${showPlayIcon ? 'fa-play' : 'fa-pause'} drop-shadow-md scale-90 hover:scale-110 transition-transform`}></i>
            </button>
          )}
        </div>

        <div className="flex-1 min-w-0 py-1">
          <p className={`text-lg font-bold truncate ${isCurrentlySelected ? 'text-white' : 'text-slate-200 group-hover:text-white transition-colors'}`}>{song.title}</p>
          <p className="text-sm text-slate-400 truncate group-hover:text-slate-300 transition-colors font-light">{song.artist}</p>
        </div>

        <div className="flex items-center space-x-2">
            <button
                onClick={(e) => {
                    e.stopPropagation();
                    onToggleFavorite();
                }}
                className={`flex-shrink-0 w-11 h-11 flex items-center justify-center rounded-full border transition-all duration-300 hover:scale-110 backdrop-blur-sm ${isFavorite 
                    ? 'bg-red-500/20 border-red-500/50 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.2)]' 
                    : 'bg-white/5 border-white/5 text-slate-400 hover:bg-white/10 hover:text-red-400 hover:border-red-400/30'}`}
                title={isFavorite ? "Remove from favorites" : "Add to favorites"}
            >
                <i className={`${isFavorite ? 'fa-solid' : 'fa-regular'} fa-heart text-xl`}></i>
            </button>

            <a
            href={song.spotifyUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-shrink-0 w-11 h-11 flex items-center justify-center rounded-full bg-white/5 border border-white/5 text-slate-400 hover:bg-[#1DB954] hover:text-white hover:border-[#1DB954] transition-all duration-300 hover:scale-110 mr-2 backdrop-blur-sm"
            title="Listen on Spotify"
            >
            <i className="fa-brands fa-spotify text-xl"></i>
            </a>
