import React, { useState, useEffect, useRef } from 'react';

interface MoodInputFormProps {
  onSubmit: (text: string) => void;
  isLoading: boolean;
}

const MoodInputForm: React.FC<MoodInputFormProps> = ({ onSubmit, isLoading }) => {
  const [text, setText] = useState('');
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = false;
        recognitionRef.current.interimResults = true;
        recognitionRef.current.lang = 'en-US';

        recognitionRef.current.onstart = () => setIsListening(true);
        recognitionRef.current.onend = () => setIsListening(false);
        recognitionRef.current.onresult = (event: any) => {
            const transcript = event.results[0][0].transcript;
            setText(transcript);

            if (event.results[0].isFinal) {
                // Auto-submit when speech is final for a seamless experience
                recognitionRef.current.stop();
                onSubmit(transcript);
            }
        };
        recognitionRef.current.onerror = (event: any) => {
            console.error("Speech recognition error", event.error);
            setIsListening(false);
            if (event.error === 'not-allowed') {
                alert("Microphone access was denied. Please allow microphone access in your browser settings to use voice input.");
            } else if (event.error === 'no-speech') {
                // Ignore no-speech error, just stop listening
            } else {
                 // For other errors, maybe show a toast or just log
            }
        };
    }
  }, [onSubmit]);

  const handleMicClick = () => {
    if (!recognitionRef.current) {
        alert("Voice input is not supported in this browser.");
        return;
    }
    if (isListening) {
        recognitionRef.current.stop();
    } else {
        setText(''); // Clear previous text
        recognitionRef.current.start();
    }
  };

  const emojiMoods = [
    { emoji: '😀', label: 'Happy' },
    { emoji: '😢', label: 'Sad' },
    { emoji: '😡', label: 'Angry' },
    { emoji: '🥳', label: 'Party' },
    { emoji: '😴', label: 'Tired' },
    { emoji: '😎', label: 'Cool' },
    { emoji: '🥰', label: 'Love' },
    { emoji: '🧘', label: 'Calm' },
    { emoji: '🤯', label: 'Mindblown' },
    { emoji: '👻', label: 'Spooky' },
    { emoji: '🥺', label: 'Emotional' },
    { emoji: '😤', label: 'Determined' },
  ];

  const handleEmojiClick = (emoji: string) => {
    setText(prev => {
        const separator = prev.length > 0 ? ' ' : '';
        return prev + separator + emoji;
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onSubmit(text);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-2xl mx-auto space-y-8 relative z-10">
      <div className="relative group">
        <div className={`absolute -inset-1 bg-gradient-to-r from-indigo-500 to-fuchsia-500 rounded-2xl opacity-0 group-hover:opacity-30 transition duration-1000 blur-lg ${isListening ? 'animate-pulse opacity-50' : ''}`}></div>

        <div className={`relative w-full h-36 bg-white/60 dark:bg-white/5 backdrop-blur-xl border border-slate-200 dark:border-white/10 rounded-2xl overflow-hidden flex flex-col transition-all duration-300 shadow-xl ${isListening ? 'border-indigo-500/30 bg-white/80 dark:bg-white/10' : 'hover:border-indigo-300 dark:hover:border-white/20'}`}>
            <textarea
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder={isListening ? "Listening..." : "Describe your mood, speak it, or pick an emoji..."}
                className="w-full h-full p-6 bg-transparent text-slate-800 dark:text-slate-100 placeholder-slate-500 dark:placeholder-slate-400/70 focus:outline-none resize-none pr-16 text-lg font-light tracking-wide"
                disabled={isLoading}
            />

            <button
                type="button"
                onClick={handleMicClick}
                disabled={isLoading}
                className={`absolute bottom-4 right-4 w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 backdrop-blur-sm border border-slate-200 dark:border-white/10 ${isListening ? 'bg-red-500/80 text-white animate-pulse shadow-[0_0_20px_rgba(239,68,68,0.4)]' : 'bg-white/50 dark:bg-white/5 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-white hover:bg-white/80 dark:hover:bg-white/10 hover:scale-105'}`}
                title={isListening ? "Stop Listening" : "Start Voice Input"}
            >
                <i className={`fa-solid ${isListening ? 'fa-microphone-lines' : 'fa-microphone'} text-lg`}></i>
            </button>

            {isListening && (
                <div className="absolute top-4 right-4 flex space-x-1">
                    <span className="w-1.5 h-1.5 bg-indigo-500 dark:bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-indigo-500 dark:bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-indigo-500 dark:bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                </div>
            )}
        </div>
      </div>

      {/* Emoji Bar */}
      <div className="space-y-4">
        <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest text-center opacity-80">Quick Mood Detection</p>
        <div className="flex flex-wrap gap-3 justify-center">
            {emojiMoods.map((item, index) => (
                <button
                    key={index}
                    type="button"
                    onClick={() => handleEmojiClick(item.emoji)}
                    disabled={isLoading}
                    className="group relative w-14 h-14 flex items-center justify-center bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl hover:bg-white dark:hover:bg-white/10 hover:border-indigo-300 dark:hover:border-white/20 hover:-translate-y-1 transition-all duration-200 backdrop-blur-md shadow-lg"
                    title={item.label}
                >
                    <span className="text-2xl filter grayscale-[0.3] group-hover:grayscale-0 group-hover:scale-125 transition-all duration-200">{item.emoji}</span>
                    <div className="absolute inset-0 bg-indigo-500/10 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity blur-md -z-10"></div>
                </button>
            ))}
        </div>
      </div>

      <button
        type="submit"
        disabled={isLoading || !text.trim()}
        className="w-full flex items-center justify-center h-[56px] px-6 bg-gradient-to-r from-indigo-600 to-fuchsia-600 hover:from-indigo-500 hover:to-fuchsia-500 text-white font-semibold rounded-2xl shadow-lg shadow-indigo-500/20 disabled:opacity-50 disabled:shadow-none disabled:cursor-not-allowed transform hover:-translate-y-0.5 transition-all duration-300 hover:shadow-[0_0_30px_rgba(99,102,241,0.4)] border border-white/10"
      >
        {isLoading ? (
          <>
            <i className="fa-solid fa-spinner fa-spin mr-3"></i>
            Analyzing Mood...
          </>
        ) : (
          <>
            <i className="fa-solid fa-wand-magic-sparkles mr-3"></i>
            Get Recommendations
          </>
        )}
      </button>
    </form>
  );
};

