interface MusicRecommenderProps {
  isDark: boolean;
  toggleTheme: () => void;
}

const MusicRecommender: React.FC<MusicRecommenderProps> = ({ isDark, toggleTheme }) => {
  // Navigation State
  const [view, setView] = useState<'home' | 'favorites' | 'analytics'>('home');

  // Data State
  const [recommendations, setRecommendations] = useState<Song[] | null>(null);
  const [mood, setMood] = useState<Mood | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // Favorites State
  const [favorites, setFavorites] = useState<Song[]>(() => {
    try {
      const saved = localStorage.getItem('favorites');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load favorites from local storage", e);
      return [];
    }
  });

  // History State for Analytics
  const [moodHistory, setMoodHistory] = useState<MoodEntry[]>(() => {
    try {
      const saved = localStorage.getItem('moodHistory');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load mood history", e);
      return [];
    }
  });

  // Player State
  const [playerSource, setPlayerSource] = useState<'recommendations' | 'favorites'>('recommendations');
  const [currentSongIndex, setCurrentSongIndex] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [volume, setVolume] = useState(1);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [isQueueOpen, setIsQueueOpen] = useState(false);

  // Derived State
  const activePlaylist = useMemo(() => {
    return playerSource === 'recommendations' ? recommendations : favorites;
  }, [playerSource, recommendations, favorites]);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const handleNextSongRef = useRef<() => void>();

  // Persist favorites
  useEffect(() => {
    localStorage.setItem('favorites', JSON.stringify(favorites));
  }, [favorites]);

  // Persist history
  useEffect(() => {
    localStorage.setItem('moodHistory', JSON.stringify(moodHistory));
  }, [moodHistory]);

  const toggleFavorite = (song: Song) => {
    setFavorites(prev => {
      const exists = prev.some(f => f.title === song.title && f.artist === song.artist);
      if (exists) {
        return prev.filter(f => !(f.title === song.title && f.artist === song.artist));
      } else {
        return [...prev, song];
      }
    });
  };

  const isSongFavorite = (song: Song) => {
    return favorites.some(f => f.title === song.title && f.artist === song.artist);
  };

  const findNextPlayableSong = (startIndex: number, direction: 1 | -1, playlist: Song[] | null): number | null => {
    if (!playlist || playlist.length < 2) return null;
    let nextIndex = (startIndex + direction + playlist.length) % playlist.length;
    const initialIndex = startIndex;
    while (!playlist[nextIndex].previewUrl) {
        nextIndex = (nextIndex + direction + playlist.length) % playlist.length;
        if (nextIndex === initialIndex) return null; // Cycled through all songs, none are playable
    }
    return nextIndex;
  };

  const handleNextSong = () => {
    if (currentSongIndex === null || !activePlaylist) return;
    const nextIndex = findNextPlayableSong(currentSongIndex, 1, activePlaylist);
    if (nextIndex !== null) {
      setCurrentSongIndex(nextIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false);
    }
  };

  useEffect(() => {
    handleNextSongRef.current = handleNextSong;
  });

  // Audio setup
  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = volume;

    const audio = audioRef.current;

    const onTimeUpdate = () => {
      if (audio.duration) {
        setProgress((audio.currentTime / audio.duration) * 100);
        setCurrentTime(audio.currentTime);
      }
    };
    const onLoadedMetadata = () => {
      setDuration(audio.duration);
    };

    const onEnded = () => {
      handleNextSongRef.current?.();
    };

    const onError = (e: Event) => {
      const target = e.target as HTMLAudioElement;
      if (target && target.src) {
          console.error("Error playing audio source. Skipping to the next available song.", target.src);
          handleNextSongRef.current?.();
      }
    };

    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('loadedmetadata', onLoadedMetadata);
    audio.addEventListener('ended', onEnded);
    audio.addEventListener('error', onError);

    return () => {
      audio.removeEventListener('timeupdate', onTimeUpdate);
      audio.removeEventListener('loadedmetadata', onLoadedMetadata);
      audio.removeEventListener('ended', onEnded);
      audio.removeEventListener('error', onError);
      audio.pause();
    };
  }, []);

  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.volume = volume;
    }
  }, [volume]);

  // Playback control
  useEffect(() => {
    if (!activePlaylist || currentSongIndex === null || !audioRef.current) return;

    const song = activePlaylist[currentSongIndex];
    if (song?.previewUrl) {
      if (audioRef.current.src !== song.previewUrl) {
        audioRef.current.src = song.previewUrl;
      }

      if (isPlaying) {
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
            playPromise.catch(e => {
                console.warn("Audio playback interrupted or prevented:", e);
            });
        }
      } else {
        audioRef.current.pause();
      }
    } else if (isPlaying) {
      handleNextSongRef.current?.();
    } else {
      setIsPlaying(false);
      audioRef.current.pause();
    }
  }, [currentSongIndex, isPlaying, activePlaylist]);


  const handleSelectSong = (index: number, source: 'recommendations' | 'favorites') => {
    const targetPlaylist = source === 'recommendations' ? recommendations : favorites;

    if (!targetPlaylist?.[index]?.previewUrl) return;

    if (playerSource === source && currentSongIndex === index) {
      setIsPlaying(!isPlaying);
    } else {
      setPlayerSource(source);
      setCurrentSongIndex(index);
      setIsPlaying(true);
    }
  };

  const handlePlayPause = () => {
    if (currentSongIndex !== null) {
      setIsPlaying(!isPlaying);
    }
  };

  const handlePrevSong = () => {
    if (currentSongIndex === null || !activePlaylist) return;
    const prevIndex = findNextPlayableSong(currentSongIndex, -1, activePlaylist);
    if (prevIndex !== null) {
      setCurrentSongIndex(prevIndex);
      setIsPlaying(true);
    } else {
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (audioRef.current && duration) {
        const newProgress = Number(e.target.value);
        const newTime = (newProgress / 100) * duration;
        audioRef.current.currentTime = newTime;
        setProgress(newProgress);
    }
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = Number(e.target.value);
    setVolume(newVolume);
  };

  const handleSubmit = async (text: string) => {
    setIsLoading(true);
    setError(null);
    setRecommendations(null);
    setMood(null);
    setIsQueueOpen(false);
    setView('home'); // Switch to home view on new search

    if (audioRef.current) {
        audioRef.current.pause();
    }
    // Only reset player if we are currently playing from recommendations, as they are about to be wiped
    if (playerSource === 'recommendations') {
        setCurrentSongIndex(null);
        setIsPlaying(false);
        setProgress(0);
        setCurrentTime(0);
        setDuration(0);
    }

    try {
      const response = await getMoodAndRecommendations(text);
      setRecommendations(response.songs);
      setMood(response.mood);

      // Update History
      const newEntry: MoodEntry = { mood: response.mood, timestamp: Date.now() };
      setMoodHistory(prev => [...prev, newEntry]);

      // Automatically switch context to new recommendations
      setPlayerSource('recommendations');
    } catch (err: unknown) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError("An unexpected error occurred.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleShuffle = () => {
    if (activePlaylist) {
        const shuffled = [...activePlaylist];
        let currentIndex = shuffled.length;
        let randomIndex;
        while (currentIndex !== 0) {
            randomIndex = Math.floor(Math.random() * currentIndex);
            currentIndex--;
            [shuffled[currentIndex], shuffled[randomIndex]] = [
            shuffled[randomIndex], shuffled[currentIndex]];
        }

        // Update the source array based on what we are looking at/playing
        if (playerSource === 'recommendations') {
            setRecommendations(shuffled);
        } else {
            setFavorites(shuffled);
        }
        setCurrentSongIndex(0);
        setIsPlaying(false); 
    }
  };

  const handleReorder = (fromIndex: number, toIndex: number) => {
    if (!activePlaylist) return;

    const newSongs = [...activePlaylist];
    [newSongs[fromIndex], newSongs[toIndex]] = [newSongs[toIndex], newSongs[fromIndex]];

    if (playerSource === 'recommendations') {
        setRecommendations(newSongs);
    } else {
        setFavorites(newSongs);
    }

    if (currentSongIndex === fromIndex) {
        setCurrentSongIndex(toIndex);
    } else if (currentSongIndex === toIndex) {
        setCurrentSongIndex(fromIndex);
    }
  };

  const getMoodEmoji = (currentMood: Mood | null): string => {
    switch (currentMood) {
      case Mood.Happy: return '😄';
      case Mood.Sad: return '😢';
      case Mood.Angry: return '😠';
      case Mood.Relaxed: return '😌';
      case Mood.Energetic: return '⚡️';
      case Mood.Lonely: return '😔';
      case Mood.Hopeful: return '✨';
      case Mood.Stressed: return '😩';
      case Mood.Romantic: return '😍';
      case Mood.Focused: return '🎯';
      case Mood.Nostalgic: return '🕰️';
      case Mood.Anxious: return '😟';
      default: return '🎶';
    }
  };

  const currentSong = currentSongIndex !== null && activePlaylist ? activePlaylist[currentSongIndex] : null;

  return (
    <div style={{ animation: `fadeIn 0.5s ease-out forwards`}} className="pb-32 relative z-10">
      <Header currentView={view} onViewChange={setView} isDark={isDark} toggleTheme={toggleTheme} />

      <main className="flex-grow container mx-auto px-4 py-8 flex flex-col items-center">

        {/* HOME VIEW */}
        {view === 'home' && (
          <>
            <div className="w-full">
              <MoodInputForm onSubmit={handleSubmit} isLoading={isLoading} />
            </div>

            <div className="w-full max-w-3xl mt-12">
              {isLoading && <Loader />}

              {error && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-600 dark:text-red-200 p-6 rounded-2xl text-center backdrop-blur-md shadow-xl" role="alert">
                  <i className="fa-solid fa-triangle-exclamation text-2xl mb-2 text-red-500 dark:text-red-400"></i>
                  <p className="font-semibold">Oops! Something went wrong.</p>
                  <p className="text-sm mt-1 opacity-80">{error}</p>
                </div>
              )}

              {recommendations && mood && !isLoading && (
                <div className="space-y-6 animate-fadeInUp">
                  <div className="bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl p-8 shadow-2xl backdrop-blur-xl">
                    <div className="flex flex-col sm:flex-row justify-between items-center gap-4 mb-2">
                        <div className="flex items-center gap-4">
                            <div className="text-5xl drop-shadow-lg">{getMoodEmoji(mood)}</div>
                            <div>
                                 <h2 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight">
                                    {mood} <span className="text-slate-500 dark:text-slate-400 font-light">Vibes</span>
                                </h2>
                                <p className="text-indigo-600 dark:text-indigo-200 text-sm font-light mt-1">
                                    Found {recommendations.length} tracks matching your energy
                                </p>
                            </div>
                        </div>

                        {recommendations.length > 1 && (
                            <button
                                onClick={handleShuffle}
                                className="flex items-center gap-2 px-5 py-2.5 bg-white/50 dark:bg-white/5 hover:bg-white/80 dark:hover:bg-white/10 text-slate-600 dark:text-slate-200 rounded-xl transition-all text-sm font-medium border border-slate-200 dark:border-white/10 hover:border-slate-300 dark:hover:border-white/20 backdrop-blur-md"
                            >
                                <i className="fa-solid fa-shuffle"></i>
                                Shuffle
                            </button>
                        )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {recommendations.map((song, index) => (
                      <SongCard 
                        key={`${song.title}-${song.artist}-${index}`} 
                        song={song} 
                        index={index}
                        onSelectSong={(idx) => handleSelectSong(idx, 'recommendations')}
                        isCurrentlySelected={playerSource === 'recommendations' && currentSongIndex === index}
                        isPlaying={isPlaying}
                        isFavorite={isSongFavorite(song)}
                        onToggleFavorite={() => toggleFavorite(song)}
                      />
                    ))}
                  </div>
                </div>
              )}

              {!isLoading && !error && !recommendations && (
                 <div className="text-center text-slate-400 mt-12 p-12 border border-dashed border-slate-300 dark:border-slate-700/50 rounded-3xl bg-white/40 dark:bg-white/5 backdrop-blur-sm">
                    <div className="w-20 h-20 bg-white/50 dark:bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-200 dark:border-white/10">
                        <i className="fa-solid fa-headphones text-3xl text-slate-400 dark:text-slate-500"></i>
                    </div>
                    <p className="text-xl font-medium text-slate-600 dark:text-slate-300">Your personalized playlist awaits.</p>
                    <p className="text-sm text-slate-500 mt-2 font-light">Enter your mood above to get started.</p>
                 </div>
              )}
            </div>
          </>
        )}

        {/* FAVORITES VIEW */}
        {view === 'favorites' && (
          <div className="w-full max-w-3xl animate-fadeInUp">
            <div className="bg-gradient-to-r from-red-500/10 to-indigo-500/10 dark:from-red-900/40 dark:to-indigo-900/40 border border-slate-200 dark:border-white/10 rounded-2xl p-8 shadow-2xl backdrop-blur-xl mb-8">
                <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4">
                        <div className="w-16 h-16 rounded-xl bg-red-500/10 dark:bg-red-500/20 flex items-center justify-center border border-red-500/20 dark:border-red-500/30 shadow-[0_0_20px_rgba(239,68,68,0.2)]">
                             <i className="fa-solid fa-heart text-3xl text-red-500 dark:text-red-400 drop-shadow-md"></i>
                        </div>
                        <div>
                             <h2 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight">
                                Your <span className="text-red-500 dark:text-red-400">Collection</span>
                            </h2>
                            <p className="text-indigo-600 dark:text-indigo-200 text-sm font-light mt-1">
                                {favorites.length} {favorites.length === 1 ? 'song' : 'songs'} saved to your library
                            </p>
                        </div>
                    </div>

                    {favorites.length > 1 && (
                        <button
                            onClick={handleShuffle}
                            className="flex items-center gap-2 px-5 py-2.5 bg-white/50 dark:bg-white/5 hover:bg-white/80 dark:hover:bg-white/10 text-slate-600 dark:text-slate-200 rounded-xl transition-all text-sm font-medium border border-slate-200 dark:border-white/10 hover:border-slate-300 dark:hover:border-white/20 backdrop-blur-md"
                        >
                            <i className="fa-solid fa-shuffle"></i>
                            Shuffle
                        </button>
                    )}
                </div>
            </div>

            {favorites.length > 0 ? (
                <div className="grid grid-cols-1 gap-4">
                {favorites.map((song, index) => (
                    <SongCard 
                    key={`${song.title}-${song.artist}-${index}`} 
                    song={song} 
                    index={index}
                    onSelectSong={(idx) => handleSelectSong(idx, 'favorites')}
                    isCurrentlySelected={playerSource === 'favorites' && currentSongIndex === index}
                    isPlaying={isPlaying}
                    isFavorite={true}
                    onToggleFavorite={() => toggleFavorite(song)}
                    />
                ))}
                </div>
            ) : (
                <div className="text-center text-slate-400 mt-12 p-12 border border-dashed border-slate-300 dark:border-slate-700/50 rounded-3xl bg-white/40 dark:bg-white/5 backdrop-blur-sm">
                    <div className="w-20 h-20 bg-white/50 dark:bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-200 dark:border-white/10">
                        <i className="fa-regular fa-heart text-3xl text-slate-400 dark:text-slate-500"></i>
                    </div>
                    <p className="text-xl font-medium text-slate-600 dark:text-slate-300">No favorites yet.</p>
                    <p className="text-sm text-slate-500 mt-2 font-light">Start discovering music and tap the heart icon to save songs here.</p>
                    <button 
                        onClick={() => setView('home')}
                        className="mt-6 px-6 py-2 bg-indigo-600/10 dark:bg-indigo-600/20 hover:bg-indigo-600/20 dark:hover:bg-indigo-600/40 text-indigo-600 dark:text-indigo-300 rounded-xl border border-indigo-500/20 dark:border-indigo-500/30 transition-all duration-300"
                    >
                        Go Discover
                    </button>
                </div>
            )}
          </div>
        )}

        {/* ANALYTICS VIEW */}
        {view === 'analytics' && (
            <AnalyticsDashboard 
                history={moodHistory}
                onGoBack={() => setView('home')}
            />
        )}

      </main>
      <Footer />

      {activePlaylist && (
        <SongQueue 
            songs={activePlaylist}
            currentSongIndex={currentSongIndex}
            isOpen={isQueueOpen}
            onClose={() => setIsQueueOpen(false)}
            onSelect={(idx) => handleSelectSong(idx, playerSource)}
            onReorder={handleReorder}
        />
      )}

      <AudioPlayer 
        song={currentSong}
        isPlaying={isPlaying}
        progress={progress}
        volume={volume}
        duration={duration}
        currentTime={currentTime}
        onPlayPause={handlePlayPause}
        onNext={handleNextSong}
        onPrev={handlePrevSong}
        onSeek={handleSeek}
        onVolumeChange={handleVolumeChange}
        onToggleQueue={() => setIsQueueOpen(!isQueueOpen)}
        isQueueOpen={isQueueOpen}
      />
    </div>
  );
};

export default MusicRecommender;

import React, { useMemo } from 'react';
import { Mood } from '../types';

export interface MoodEntry {
  mood: Mood;
  timestamp: number;
}

interface AnalyticsDashboardProps {
  history: MoodEntry[];
  onGoBack: () => void;
}

const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ history, onGoBack }) => {
  // --- Data Processing ---

  const totalSessions = history.length;

  // 1. Mood Frequency (Distribution)
  const moodCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    history.forEach(entry => {
      counts[entry.mood] = (counts[entry.mood] || 0) + 1;
    });
    return counts;
  }, [history]);

  // Top Mood
  const topMood = useMemo(() => {
    if (totalSessions === 0) return 'N/A';
    return Object.entries(moodCounts).reduce((a, b) => (b[1] > a[1] ? b : a))[0];
  }, [moodCounts, totalSessions]);

  // Sort moods by frequency for the chart
  const sortedMoods = useMemo(() => {
    return Object.entries(moodCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5); // Top 5
  }, [moodCounts]);

  // 2. Weekly Activity (Last 7 days)
  const dailyActivity = useMemo(() => {
    const days = 7;
    const activity = new Array(days).fill(0);
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    history.forEach(entry => {
      const entryDate = new Date(entry.timestamp);
      entryDate.setHours(0, 0, 0, 0);
      const diffTime = Math.abs(today.getTime() - entryDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

      if (diffDays < days) {
        // diffDays is 0 for today, 1 for yesterday... index needs to be reversed for chart (0 is 6 days ago)
        activity[days - 1 - diffDays]++;
      }
    });
    return activity;
  }, [history]);

  const maxActivity = Math.max(...dailyActivity, 1);

  // Helper for Chart colors
  const getMoodColor = (moodName: string) => {
    // Simple hash to color or preset map could work, using distinct Tailwind-ish hexes
    const colors: Record<string, string> = {
      [Mood.Happy]: '#fbbf24', // Amber
      [Mood.Sad]: '#60a5fa',   // Blue
      [Mood.Angry]: '#ef4444', // Red
      [Mood.Relaxed]: '#34d399', // Emerald
      [Mood.Energetic]: '#f472b6', // Pink
      [Mood.Romantic]: '#f87171', // Red-400
      [Mood.Focused]: '#818cf8', // Indigo
      [Mood.Lonely]: '#94a3b8', // Slate
    };
    return colors[moodName] || '#a78bfa'; // Default Purple
  };

  const getDayLabel = (index: number) => {
    const date = new Date();
    date.setDate(date.getDate() - (6 - index));
    return date.toLocaleDateString('en-US', { weekday: 'short' });
  };

  if (history.length === 0) {
    return (
      <div className="w-full max-w-4xl animate-fadeInUp">
        <div className="text-center text-slate-400 mt-12 p-12 border border-dashed border-slate-300 dark:border-slate-700/50 rounded-3xl bg-white/40 dark:bg-white/5 backdrop-blur-sm">
          <div className="w-20 h-20 bg-white/50 dark:bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-200 dark:border-white/10">
              <i className="fa-solid fa-chart-line text-3xl text-slate-400 dark:text-slate-500"></i>
          </div>
          <p className="text-xl font-medium text-slate-600 dark:text-slate-300">No data yet.</p>
          <p className="text-sm text-slate-500 mt-2 font-light">Start using the app to track your mood history.</p>
          <button 
              onClick={onGoBack}
              className="mt-6 px-6 py-2 bg-indigo-600/10 dark:bg-indigo-600/20 hover:bg-indigo-600/20 dark:hover:bg-indigo-600/40 text-indigo-600 dark:text-indigo-300 rounded-xl border border-indigo-500/20 dark:border-indigo-500/30 transition-all duration-300"
          >
              Start Exploring
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-5xl animate-fadeInUp space-y-6 pb-24">

      {/* 1. Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {/* Total Sessions */}
        <div className="bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 p-6 rounded-2xl shadow-lg backdrop-blur-md flex items-center justify-between">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">Total Vibe Checks</p>
            <p className="text-4xl font-bold text-slate-800 dark:text-white mt-1">{totalSessions}</p>
          </div>
          <div className="w-12 h-12 bg-indigo-500/10 dark:bg-indigo-500/20 rounded-xl flex items-center justify-center text-indigo-500 dark:text-indigo-400">
             <i className="fa-solid fa-layer-group text-xl"></i>
          </div>
        </div>

        {/* Top Mood */}
        <div className="bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 p-6 rounded-2xl shadow-lg backdrop-blur-md flex items-center justify-between">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">Top Mood</p>
            <p className="text-4xl font-bold text-slate-800 dark:text-white mt-1 truncate">{topMood}</p>
          </div>
           <div className="w-12 h-12 bg-fuchsia-500/10 dark:bg-fuchsia-500/20 rounded-xl flex items-center justify-center text-fuchsia-500 dark:text-fuchsia-400">
             <i className="fa-solid fa-crown text-xl"></i>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* 2. Mood Distribution Chart */}
        <div className="bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 p-6 rounded-2xl shadow-lg backdrop-blur-md flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Most Common Moods</h3>
          <div className="flex-1 flex flex-col justify-center space-y-4">
            {sortedMoods.map(([mood, count], index) => {
               const percentage = (count / totalSessions) * 100;
               return (
                 <div key={mood} className="space-y-1">
                   <div className="flex justify-between text-xs font-medium text-slate-600 dark:text-slate-300">
                     <span>{mood}</span>
                     <span>{count} ({Math.round(percentage)}%)</span>
                   </div>
                   <div className="w-full bg-slate-200 dark:bg-white/10 rounded-full h-2.5 overflow-hidden">
                     <div 
                        className="h-full rounded-full transition-all duration-1000 ease-out"
                        style={{ 
                          width: `${percentage}%`, 
                          backgroundColor: getMoodColor(mood),
                          animation: `slideRight 1s ease-out forwards`
                        }}
                     ></div>
                   </div>
                 </div>
               );
            })}
          </div>
        </div>

        {/* 3. Weekly Activity Graph */}
        <div className="bg-white/60 dark:bg-white/5 border border-slate-200 dark:border-white/10 p-6 rounded-2xl shadow-lg backdrop-blur-md flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Activity (Last 7 Days)</h3>
          <div className="flex-1 flex items-end justify-between gap-2 min-h-[150px] relative pb-6">
             {/* Y-axis lines (Visual only) */}
             <div className="absolute inset-0 flex flex-col justify-between pointer-events-none opacity-20">
                <div className="border-t border-slate-400 dark:border-white w-full"></div>
                <div className="border-t border-slate-400 dark:border-white w-full"></div>
                <div className="border-t border-slate-400 dark:border-white w-full"></div>
             </div>

             {dailyActivity.map((count, index) => {
                const heightPercentage = count === 0 ? 0 : (count / maxActivity) * 100;
                return (
                  <div key={index} className="flex flex-col items-center flex-1 h-full justify-end z-10 group">
                    <div 
                      className="w-full max-w-[24px] bg-indigo-400 dark:bg-indigo-500 rounded-t-lg transition-all duration-700 ease-out hover:bg-fuchsia-400 dark:hover:bg-fuchsia-500 relative"
                      style={{ 
                          height: `${heightPercentage}%`,
