                            {isLoginMode ? "Don't have an account?" : "Already have an account?"}
                            <button 
                                onClick={() => {
                                    setIsLoginMode(!isLoginMode);
                                    setEmail('');
                                    setPassword('');
                                    setUsername('');
                                }}
                                className="ml-2 font-bold text-indigo-600 dark:text-indigo-400 hover:underline"
                            >
                                {isLoginMode ? 'Sign Up' : 'Log In'}
                            </button>
