                 song={sotd}
                 isLoading={isSotdLoading}
                 onReveal={handleRevealSOTD}
                 onPlayPause={handlePlaySOTD}
                 isPlaying={isPlaying}
                 isCurrent={playerSource === 'sotd'}
                 isFavorite={sotd ? isSongFavorite(sotd) : false}
                 onToggleFavorite={() => sotd && toggleFavorite(sotd)}
